import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../pages/CartContext';

export default function ProductCard({ product }) {
  const { addToCart, toggleWishlist, wishlist } = useCart();
  const navigate = useNavigate();
  const [added, setAdded] = useState(false);

  const isWishlisted = wishlist.includes(product.id);

  const handleAdd = (e) => {
    e.stopPropagation();
    addToCart(product);
    setAdded(true);
    setTimeout(() => setAdded(false), 1200);
  };

  const discount = product.oldPrice
    ? Math.round((1 - product.price / product.oldPrice) * 100)
    : null;

  return (
    <div
      onClick={() => navigate(`/product/${product.id}`)}
      className="group cursor-pointer transition-all duration-300 hover:-translate-y-1"
    >
      {/* IMAGE CONTAINER */}
      <div className="relative rounded-2xl overflow-hidden bg-gray-100 mb-3 shadow-sm group-hover:shadow-xl transition-all duration-300"
        style={{ aspectRatio: '0.78' }}
      >
        <img
          src={product.img}
          alt={product.name}
          className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
          loading="lazy"
        />

        {/* DARK HOVER OVERLAY */}
        <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-all duration-300" />

        {/* BADGE */}
        {product.badge && (
          <span className={`absolute top-3 left-3 z-10 text-[10px] font-bold px-3 py-1 rounded-full backdrop-blur-md ${product.badgeColor}`}>
            {product.badge}
          </span>
        )}

        {/* WISHLIST */}
        <button
          onClick={(e) => {
            e.stopPropagation();
            toggleWishlist(product.id);
          }}
          className="absolute top-3 right-3 z-10 w-9 h-9 bg-white/90 backdrop-blur-md rounded-full flex items-center justify-center shadow-md transition-all hover:scale-110"
        >
          {isWishlisted ? (
            <span className="text-red-500 text-lg">♥</span>
          ) : (
            <span className="text-gray-400 text-lg">♡</span>
          )}
        </button>

        {/* ADD TO CART */}
        <button
          onClick={handleAdd}
          className={`
            absolute bottom-3 left-3 right-3 z-10
            text-xs font-semibold tracking-wide
            py-2.5 rounded-xl
            transition-all duration-300
            ${added
              ? 'bg-green-500 text-white'
              : 'bg-white/95 backdrop-blur-md text-black hover:bg-black hover:text-white'}
          `}
        >
          {added ? '✓ Added' : 'Add to Bag'}
        </button>
      </div>

      {/* TEXT CONTENT */}
      <div className="px-1">

        {/* SERIES */}
        <div className="text-[10px] font-semibold tracking-[2px] uppercase text-gray-400 mb-1">
          {product.series}
        </div>

        {/* NAME */}
        <div className="text-sm font-semibold text-gray-900 mb-2 leading-snug line-clamp-2">
          {product.name}
        </div>

        {/* PRICE */}
        <div className="flex items-center gap-2">
          <span className="text-base font-bold text-black">
            ₹{product.price.toLocaleString('en-IN')}
          </span>

          {product.oldPrice && (
            <>
              <span className="text-xs text-gray-400 line-through">
                ₹{product.oldPrice.toLocaleString('en-IN')}
              </span>
              <span className="text-xs font-semibold text-green-600">
                {discount}% OFF
              </span>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
